'use strict'

const transaction = require('./transaction')

function runTest(parseBody, label) {
    return new Promise((resolve) => {
        const txn = transaction.createTransaction('test-uuid', {})

        if (parseBody) {
            txn.parse_body = true
            txn.attachment_hooks(() => {})
        }

        // Simulate receiving an email
        txn.add_data('From: sender@example.com\n')
        txn.add_data('To: recipient@example.com\n')
        txn.add_data('Subject: Test\n')
        txn.add_data('\n')
        txn.add_data('Hello, this is the body.\n')

        txn.end_data(() => {
            // Now add headers (like in data_post hook)
            txn.add_header('X-Added-Header', 'added-value')
            txn.add_leading_header('X-Leading-Header', 'leading-value')

            // Get the final message data
            txn.message_stream.get_data((data) => {
                const output = data.toString()
                console.log(`\n=== ${label} ===`)
                console.log(output)
                console.log(`=== END ${label} ===`)

                // Check if the headers appear BEFORE the body
                const bodyIndex = output.indexOf('Hello, this is the body.')
                const addedHeaderIndex = output.indexOf('X-Added-Header')
                const leadingHeaderIndex = output.indexOf('X-Leading-Header')

                console.log(`Body position: ${bodyIndex}`)
                console.log(`X-Added-Header position: ${addedHeaderIndex}`)
                console.log(`X-Leading-Header position: ${leadingHeaderIndex}`)

                if (addedHeaderIndex > bodyIndex) {
                    console.log(`FAIL [${label}]: X-Added-Header appears AFTER body!`)
                } else if (addedHeaderIndex === -1) {
                    console.log(`FAIL [${label}]: X-Added-Header not found!`)
                } else {
                    console.log(`PASS [${label}]: X-Added-Header appears before body`)
                }

                if (leadingHeaderIndex > bodyIndex) {
                    console.log(`FAIL [${label}]: X-Leading-Header appears AFTER body!`)
                } else if (leadingHeaderIndex === -1) {
                    console.log(`FAIL [${label}]: X-Leading-Header not found!`)
                } else {
                    console.log(`PASS [${label}]: X-Leading-Header appears before body`)
                }

                resolve()
            })
        })
    })
}

async function main() {
    await runTest(false, 'parse_body=false')
    await runTest(true, 'parse_body=true')
}

main().catch(console.error)

